using System;

class Car
{
    public string Brand;
    public string Color;

    public void Drive()
    {
        Console.WriteLine($"{Color} rəngli {Brand} sürülür.");
    }
}

class Program
{
    static void Main(string[] args)
    {
        Car myCar = new Car();
        myCar.Brand = "Toyota";
        myCar.Color = "Qırmızı";

        Console.WriteLine($"Avtomobil: {myCar.Brand}, Rəng: {myCar.Color}");
        myCar.Drive();
    }
}
// Output:
// Avtomobil: Toyota, Rəng: Qırmızı
// Qırmızı rəngli Toyota sürülür.

using System;

class Person
{
    private string name;

    public string Name
    {
        get { return name; }
        set { name = value ?? "Adsız"; }
    }

    public int Age { get; set; }

    public void Introduce()
    {
        Console.WriteLine($"Salam, mən {Name}, {Age} yaşım var.");
    }
}

class Program
{
    static void Main(string[] args)
    {
        Person person = new Person();
        person.Name = "Aysel";
        person.Age = 25;
        person.Introduce();

        Person anotherPerson = new Person();
        anotherPerson.Name = null; // Adsız olacaq
        anotherPerson.Age = 30;
        anotherPerson.Introduce();
    }
}
// Output:
// Salam, mən Aysel, 25 yaşım var.
// Salam, mən Adsız, 30 yaşım var.

