using System;

class BankAccount
{
    private decimal balance;

    public decimal Balance
    {
        get { return balance; }
        private set { if (value >= 0) balance = value; }
    }

    public BankAccount(decimal initialBalance)
    {
        Balance = initialBalance;
    }

    public void Deposit(decimal amount)
    {
        if (amount > 0)
            Balance += amount;
        Console.WriteLine($"{amount} əlavə edildi. Yeni balans: {Balance}");
    }
}

class Program
{
    static void Main(string[] args)
    {
        BankAccount account = new BankAccount(1000);
        account.Deposit(500);
        // account.Balance = -100; // Xəta: Balance yalnız sinif daxilində dəyişdirilə bilər
        Console.WriteLine($"Cari balans: {account.Balance}");
    }
}
// Output:
// 500 əlavə edildi. Yeni balans: 1500
// Cari balans: 1500

